import React from 'react';
import optImg from '../assets/opt.JPG';

const Home = () => {
    return (
        <div className="flex flex-col items-center justify-center min-h-screen bg-gradient-to-br from-gray-100 to-blue-100">
            {/* Profile Image */}
            <img
                src={optImg}
                alt="Profile"
                className="w-36 h-36 rounded-full mb-6 shadow-2xl border-4 border-blue-300"
            />
            {/* About Me Section */}
            <h1 className="text-5xl font-extrabold mb-4 text-blue-700 drop-shadow">Welcome to My Portfolio</h1>
            <div className="bg-white rounded-xl shadow-lg p-6 mb-6 max-w-xl">
                <p className="text-lg text-center">
                    <span className="font-semibold text-blue-600">About Me:</span> <br />
                    Hi, I'm Veera! I am a passionate developer with experience in JavaScript, React, Tailwind CSS, and Node.js. I love building modern web applications and learning new technologies.
                </p>
            </div>
            <h2 className="text-2xl font-semibold mb-2 text-blue-600">Skills:</h2>
            <ul className="list-disc list-inside mb-8 text-lg">
                <li>JavaScript</li>
                <li>React</li>
                <li>Tailwind CSS</li>
                <li>Node.js</li>
            </ul>
            <h2 className="text-2xl font-semibold mb-2 text-blue-600">Projects:</h2>
            <p className="mb-4">Check out some of my projects below:</p>
            <a href="/projects" className="text-blue-500 hover:underline font-medium">View Projects</a>
        </div>
    );
};

export default Home;
